-- Ken's Hardened V2 Fix

local b64_0xlIl1I1 = {}
local char_0xIIllll='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xlIl1Il=1,#char_0xIIllll do b64_0xlIl1I1[char_0xIIllll:sub(i_0xlIl1Il,i_0xlIl1Il)] = i_0xlIl1Il - 1 end

function b64_0xlIl1I1.dec_0xll1l1I(d_0xllllll)
    d_0xllllll = string.gsub(d_0xllllll, '[^'..char_0xIIllll..'=]', '')
    local r_0xIlIlI1 = {}
    for i_0xlIl1Il=1, #d_0xllllll, 4 do
        local c_0x111lII = b64_0xlIl1I1[d_0xllllll:sub(i_0xlIl1Il,i_0xlIl1Il)] or 0
        local c_0xIIIlII = b64_0xlIl1I1[d_0xllllll:sub(i_0xlIl1Il+1,i_0xlIl1Il+1)] or 0
        local c_0x1III1l, c_0xlIlIll = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xllllll:sub(i_0xlIl1Il+2,i_0xlIl1Il+2)
        if ch3 == "=" then has3 = false else c_0x1III1l = b64_0xlIl1I1[ch3] or 0 end
        local ch4 = d_0xllllll:sub(i_0xlIl1Il+3,i_0xlIl1Il+3)
        if ch4 == "=" then has4 = false else c_0xlIlIll = b64_0xlIl1I1[ch4] or 0 end
        local b_0xIIlIl1 = c_0x111lII * (2^18) + c_0xIIIlII * (2^12) + c_0x1III1l * (2^6) + c_0xlIlIll
        local b_0xIIl1Il = math.floor(b_0xIIlIl1 / (2^16)) % (2^8)
        local b_0x1I1llI = math.floor(b_0xIIlIl1 / (2^8)) % (2^8)
        local b_0xII1lII = b_0xIIlIl1 % (2^8)
        table.insert(r_0xIlIlI1, string.char(b_0xIIl1Il))
        if has3 then table.insert(r_0xIlIlI1, string.char(b_0x1I1llI)) end
        if has4 then table.insert(r_0xIlIlI1, string.char(b_0xII1lII)) end
    end
    return table.concat(r_0xIlIlI1)
end


local function bxor_0xlI1lll(a_0x1llllI,b_0xllIllI)
    if bit32 then return bit32.bxor(a_0x1llllI,b_0xllIllI) end
    local r_0xI1Il1I = 0
    for i_0xlII11I = 0, 7 do
        local x_0x1lI1ll = a_0x1llllI % 2
        local y_0xIIl1lI = b_0xllIllI % 2
        if x_0x1lI1ll ~= y_0xIIl1lI then r_0xI1Il1I = r_0xI1Il1I + (2^i_0xlII11I) end
        a_0x1llllI = math.floor(a_0x1llllI / 2)
        b_0xllIllI = math.floor(b_0xllIllI / 2)
    end
    return r_0xI1Il1I
end


local function bxor_str_0xlIIlII(s_0xII1IIl, k_0x1IlllI)
    local r_0xIIIIlI = {}
    for i_0xl1llIl=1, #s_0xII1IIl do
        local b_0xlllIlI = string.byte(s_0xII1IIl, i_0xl1llIl)
        local kb_0xlll1lI = string.byte(k_0x1IlllI, (i_0xl1llIl-1) % #k_0x1IlllI + 1)
        r_0xIIIIlI[i_0xl1llIl] = string.char(bxor_0xlI1lll(b_0xlllIlI, kb_0xlll1lI))
    end
    return table.concat(r_0xIIIIlI)
end


local function getkeys_0xIlIIll()
    local seed = b64_0xlIl1I1.dec_0xll1l1I("VzdrZUtxYWY=")
    local k1_enc = b64_0xlIl1I1.dec_0xll1l1I("MU0fDxMEVRQ=")
    local k2_enc = b64_0xlIl1I1.dec_0xll1l1I("GkUCEjIWGzQ=")
    return bxor_str_0xlIIlII(k1_enc, seed), bxor_str_0xlIIlII(k2_enc, seed)
end


local function cff_0x1lllII(a_0xll1lll)
    local st_0x111IlI = 0
    local res_0xlll11I = a_0xll1lll
    while true do
        if st_0x111IlI == 0 then
            res_0xlll11I = res_0xlll11I + 1
            st_0x111IlI = 1
        elseif st_0x111IlI == 1 then
            res_0xlll11I = res_0xlll11I * 2
            st_0x111IlI = 2
        elseif st_0x111IlI == 2 then
            res_0xlll11I = res_0xlll11I - 3
            st_0x111IlI = 3
        else
            break
        end
    end
    return res_0xlll11I
end


local function chain_0xll11II(x) return x*2 end
local function chain_0xIII1ll(x) return chain_0xll11II(x)+1 end


local d_0xIl11Il = {
  {op=255, val="", is_enc=true},
}
local pc_0xll1llI = 1
local stk_0xlI1lI1 = {}
stk_0xlI1lI1._jmp = nil


local disp_0xlIlI1l = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xIlIIll()

local state_0xIIl11l = 0
while true do
    if state_0xIIl11l == 0 then  -- FETCH
        if pc_0xll1llI > #d_0xIl11Il then break end
        local inst = d_0xIl11Il[pc_0xll1llI]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xlIl1I1.dec_0xll1l1I(val)
            d = bxor_str_0xlIIlII(d, k2)
            val = bxor_str_0xlIIlII(d, k1)
        end
        stk_0xlI1lI1._jmp = nil
        pc_0xll1llI = pc_0xll1llI + 1
        cur_op_0xllll1l = opcode
        cur_val_0xlIlI1I = val
        state_0xIIl11l = 1

    elseif state_0xIIl11l == 1 then  -- EXECUTE
        local handler = disp_0xlIlI1l[cur_op_0xllll1l]
        if handler then
            handler(stk_0xlI1lI1, cur_val_0xlIlI1I)
        end
        if stk_0xlI1lI1._jmp then
            pc_0xll1llI = pc_0xll1llI + stk_0xlI1lI1._jmp
        end
        state_0xIIl11l = 0
    else
        break
    end
end
